/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(VendEditInvoice, VendInvoiceInfoLine_ETGActualPurchPrice), FormControlEventType::Modified)]
public static void VendInvoiceInfoLine_ETGActualPurchPrice_OnModified(FormControl sender, FormControlEventArgs e)
{
    if(ETGACFParameters::find().EnablePTBFContractsPurch == NoYes::Yes)
    {
        VendInvoiceInfoLine InvoiceInfoLine = sender.formRun().dataSource().cursor();
        PurchLine purchLine;

        select firstonly purchLine
            where purchLine.RecId == InvoiceInfoLine.PurchLineRecId;


        if(purchLine)
        {
            real checkPlus = 100 + purchLine.ETGPriceTolerance;
            real checkMinus = 100 - purchLine.ETGPriceTolerance;

            real ActualUnitprice = str2Num(sender.valueStr());

            real a = (purchLine.PurchPrice * checkPlus) / 100;
            real b = (purchLine.PurchPrice * checkMinus) / 100;

            if(ActualUnitprice < b || ActualUnitprice > a)
            {
                throw error("@ETG_New:ETGCrDeActualUnitPrice");
            }

        }
    }
}

/// <summary>
/// Abhinav 11-02-2025
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(VendEditInvoice, VendInvoiceInfoLine_ETGActualQty), FormControlEventType::Modified)]
public static void VendInvoiceInfoLine_ETGActualQty_OnModified(FormControl sender, FormControlEventArgs e)
{
    if(ETGACFParameters::find().EnablePTBFContractsPurch == NoYes::Yes)
    {
        VendInvoiceInfoLine InvoiceInfoLine = sender.formRun().dataSource().cursor();
        PurchLine purchLine;

        select firstonly purchLine
            where purchLine.RecId == InvoiceInfoLine.PurchLineRecId;

        if(purchLine)
        {
            real checkPlus = 100 + purchLine.OverDeliveryPct;

            real ActualUnitprice = str2Num(sender.valueStr());

            real a = (purchLine.PurchQty * checkPlus) / 100;

            if(ActualUnitprice > a)
            {
                throw error("@ETG_New:ETGOverdeliveryError");
            }

        }
    }
}

/// <summary>
/// Abhinav - 11-02-2025
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(VendEditInvoice, UpdateMatchStatus), FormControlEventType::Clicked)]
public static void UpdateMatchStatus_OnClicked(FormControl sender, FormControlEventArgs e)
{
    if(ETGACFParameters::find().EnablePTBFContractsPurch == NoYes::Yes)
    {
       // VendInvoiceInfoLine InvoiceInfoLine = sender.formRun().dataSource().cursor();
        VendInvoiceInfoLine InvoiceInfoLine = sender.formRun().dataSource('VendInvoiceInfoLine').cursor(); 
        VendInvoiceTrans    VendInvoiceTrans;
        PurchLine  purchline; 
        boolean        enableactualprice = false;
        Purchtable purchTableLoc;

        purchline = purchline::findInventTransId(InvoiceInfoLine.InventTransId);

        Select sum(Qty) from  VendInvoiceTrans where VendInvoiceTrans.InventTransId == InvoiceInfoLine.InventTransId
        && VendInvoiceTrans.PurchID == InvoiceInfoLine.OrigPurchId;

        if(purchline.ETGCrDrNoteCreated ==NoYes::Yes)
        {
            enableactualprice = false;
        }
        else
        {
            enableactualprice =  (purchline.PurchQty == (VendInvoiceTrans.Qty + InvoiceInfoLine.ReceiveNow)) ? true :false;
        }

        purchTableLoc = Purchtable::find(purchline.PurchId);

        if(purchTableLoc.PurchStatus == PurchStatus::Received)
        {
            enableactualprice = true;
        }

        if(InvoiceInfoLine.ETGActualPurchPrice == 0 && enableactualprice && InvoiceInfoLine.ETGActualQuantity == 0)
        {
            if(Box::yesNoCancel("@ETG_New:ETGEditActualUnitQuantity",dialogButton::No,"Edit actual purch price"))
            {
                throw Error("@ETG_New:ETGUpdateMatchCancelled");
            }

        }
    }
}
